patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index c55c40c88bc8..1955d4e31c32 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -2228,6 +2228,23 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
                                      /*MatchBitReversals*/ true))
         return BitOp;
     }
+    // fshl(X, 0, y) -> shl X, y
+    // fshl(X, undef, y) -> shl X, y
+    // fshr(undef, X, y) -> lshr X, y
+    KnownBits Known = computeKnownBits(Op1, /*Depth=*/0, II);
+    if (IID == Intrinsic::fshl && (match(Op1, m_ZeroInt()) || match(Op1, m_Undef()) || Known.isZero())) {
+      Value *ShAmt = II->getArgOperand(2);
+      if (isPowerOf2_32(BitWidth))
+        ShAmt = Builder.CreateAnd(ShAmt, ConstantInt::get(Ty, BitWidth - 1));
+      return BinaryOperator::CreateShl(Op0, ShAmt);
+    }
+    // fshr(undef, X, y) -> lshr X, y
+    if (IID == Intrinsic::fshr && match(Op0, m_Undef())) {
+      Value *ShAmt = II->getArgOperand(2);
+      if (isPowerOf2_32(BitWidth))
+        ShAmt = Builder.CreateAnd(ShAmt, ConstantInt::get(Ty, BitWidth - 1));
+      return BinaryOperator::CreateLShr(Op1, ShAmt);
+    }

     // Left or right might be masked.
     if (SimplifyDemandedInstructionBits(*II))

